101→    private void importFile(Uri uri) {
102→        String path = copyToCache(uri);
103→        if (path == null) return;
104→        String name = getFileName(uri).toLowerCase();
105→        if (name.endsWith(".wav") || name.endsWith(".mp3") || name.endsWith(".m4a") ||
106→            name.endsWith(".flac") || name.endsWith(".amr") || name.endsWith(".silk")) {
107→            audioPath = path;
108→            tvAudioName.setText(getFileName(uri));
109→        } else {
110→            docPath = path;
111→            tvDocName.setText(getFileName(uri));
112→        }
113→        tvStatus.setText("已从微信导入文件");
114→    }
