116→    private String copyToCache(Uri uri) {
117→        try {
118→            InputStream is = getContentResolver().openInputStream(uri);
119→            String name = getFileName(uri);
120→            File out = new File(getCacheDir(), name);
121→            FileOutputStream fos = new FileOutputStream(out);
122→            byte[] buf = new byte[8192];
123→            int n;
124→            while ((n = is.read(buf)) != -1) fos.write(buf, 0, n);
125→            fos.close();
126→            is.close();
127→            return out.getAbsolutePath();
128→        } catch (Exception e) {
129→            tvStatus.setText("文件导入失败: " + e.getMessage());
130→            return null;
131→        }
132→    }
