134→    private String getFileName(Uri uri) {
135→        String name = "file";
136→        Cursor c = getContentResolver().query(uri, null, null, null, null);
137→        if (c != null && c.moveToFirst()) {
138→            int idx = c.getColumnIndex(OpenableColumns.DISPLAY_NAME);
139→            if (idx >= 0) name = c.getString(idx);
140→            c.close();
141→        }
142→        return name;
143→    }
