145→    // ===== 读取 WAV 文件为 float 数组 =====
146→    private float[] readWav(String filepath) throws IOException {
147→        FileInputStream fis = new FileInputStream(filepath);
148→        // 跳过 WAV 头 (44字节)
149→        byte[] header = new byte[44];
150→        fis.read(header);
151→
152→        // 读取全部 PCM 数据
153→        ByteArrayOutputStream baos = new ByteArrayOutputStream();
154→        byte[] buf = new byte[8192];
155→        int n;
156→        while ((n = fis.read(buf)) != -1) baos.write(buf, 0, n);
157→        fis.close();
158→
159→        byte[] pcm = baos.toByteArray();
160→        int numSamples = pcm.length / 2;
161→        float[] samples = new float[numSamples];
162→        ByteBuffer bb = ByteBuffer.wrap(pcm).order(ByteOrder.LITTLE_ENDIAN);
163→        for (int i = 0; i < numSamples; i++) {
164→            samples[i] = bb.getShort() / 32768.0f;
165→        }
166→        return samples;
167→    }
168→
169→    // ===== Sherpa-ONNX 离线识别 =====
170→    private String transcribeSherpa(String audioFile) throws Exception {
171→        AssetManager assetManager = getAssets();
172→
173→        // 配置 Paraformer 模型
174→        OfflineParaformerModelConfig paraformerConfig = new OfflineParaformerModelConfig();
175→        paraformerConfig.setModel("models/paraformer/model.int8.onnx");
176→
177→        // 配置模型总参数
178→        OfflineModelConfig modelConfig = new OfflineModelConfig();
179→        modelConfig.setParaformer(paraformerConfig);
180→        modelConfig.setTokens("models/paraformer/tokens.txt");
181→        modelConfig.setNumThreads(4);
182→        modelConfig.setDebug(false);
183→
184→        // 配置识别器
185→        OfflineRecognizerConfig config = new OfflineRecognizerConfig();
186→        config.setModelConfig(modelConfig);
187→        config.setDecodingMethod("greedy_search");
188→
189→        // 创建识别器（使用 AssetManager 读取模型）
190→        OfflineRecognizer recognizer = new OfflineRecognizer(assetManager, config);
191→
192→        // 读取音频并识别
193→        float[] samples = readWav(audioFile);
194→        OfflineStream stream = recognizer.createStream();
195→        stream.acceptWaveform(samples, 16000);
196→        recognizer.decode(stream);
197→
198→        OfflineRecognizerResult result = recognizer.getResult(stream);
199→        String text = result.getText();
200→
201→        stream.release();
202→        recognizer.release();
203→
204→        return text != null ? text.trim() : "";
205→    }
206→
207→    private void startCompare() {
208→        if (audioPath.isEmpty() || docPath.isEmpty()) {
209→            tvStatus.setText("请先选择录音和文档");
210→            return;
211→        }
212→        btnCompare.setEnabled(false);
213→        progressBar.setVisibility(View.VISIBLE);
214→        tvStatus.setText("正在处理...");
215→
216→        new Thread(() -> {
217→            try {
218→                // 第1步：Sherpa-ONNX 离线识别
219→                runOnUiThread(() -> tvStatus.setText("正在识别语音（离线）..."));
220→                String audioText = transcribeSherpa(audioPath);
221→                Log.i(TAG, "ASR结果: " + audioText);
222→
223→                if (audioText.isEmpty()) {
224→                    runOnUiThread(() -> {
225→                        tvStatus.setText("语音识别失败：未识别到文字");
226→                        progressBar.setVisibility(View.GONE);
227→                        btnCompare.setEnabled(true);
228→                    });
229→                    return;
230→                }
231→
232→                // 第2步：Python 文本对比
233→                runOnUiThread(() -> tvStatus.setText("正在对比文本..."));
234→                Python py = Python.getInstance();
235→                PyObject engine = py.getModule("engine");
236→                PyObject result = engine.callAttr("run_compare", audioText, docPath);
237→
238→                String summary = result.callAttr("get", "summary").toString();
239→                String details = result.callAttr("get", "details").toString();
240→
241→                runOnUiThread(() -> {
242→                    tvStatus.setText("对比完成");
243→                    tvResult.setText(summary + "\n\n" + details);
244→                    scrollResult.setVisibility(View.VISIBLE);
245→                    progressBar.setVisibility(View.GONE);
246→                    btnCompare.setEnabled(true);
247→                });
248→            } catch (Exception e) {
249→                Log.e(TAG, "Error", e);
250→                runOnUiThread(() -> {
251→                    tvStatus.setText("错误: " + e.getMessage());
252→                    progressBar.setVisibility(View.GONE);
253→                    btnCompare.setEnabled(true);
254→                });
255→            }
256→        }).start();
257→    }
258→}
